UPDATE NOTIFICATION
SET status = 'IN_PROGRESS'
WHERE notification_id = #{notificationId}
  AND status = #{currentStatus}

UPDATE NOTIFICATION
SET status = 'DEAD_LETTER',
    retry_cnt = #{retryCnt},
    last_error_code = #{lastErrorCode},
    last_error_message = #{lastErrorMessage}
WHERE notification_id = #{notificationId}
